def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        if item > cap:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        base = 0
        if ratio < 0.1:
            base = np.exp(-10 * ratio) * (1.2 - ratio**1.5)
        elif 0.1 <= ratio <= 0.3:
            base = np.log1p(ratio * 7) * 3 + np.sin(ratio * 15) * 0.7 - ratio
        elif 0.3 < ratio <= 0.6:
            base = np.tanh(8 * (ratio - 0.45)) + np.cos(ratio * 12) * 0.9 + 0.5
        elif 0.6 < ratio < 0.85:
            base = (np.sin(ratio * 20) + np.exp(-5 * (1 - ratio))) * 0.8
        else:
            base = 1/(1 + np.exp(-50 * (ratio - 0.9))) + 0.3 * np.sqrt(ratio)
        penalty = 0
        for x in range(1, 10):
            mod_val = (item * x**1.5) % (cap + 1)
            frac = mod_val / (cap * (x + 1))
            if frac < 0.03:
                penalty += frac * (x**0.7)
            elif frac < 0.1:
                penalty += (frac**0.5) * x * 0.8
            elif frac < 0.3:
                penalty += np.log1p(frac) * (10 / (x + 2))
            else:
                penalty += (frac**2) / (x + ratio + 1)
        extra_penalty = 0
        for y in range(1, 7):
            threshold = 0.15 * y
            if ratio > threshold:
                val = np.exp(-y*ratio*1.5) * y**3
                extra_penalty += min(val, 2)
            else:
                val = np.log1p(ratio * y**3 + y * 2)
                extra_penalty += val / (y + 1.5)
        complexity = 0
        for m in range(1, 5):
            for n in range(1, 5):
                combined = (ratio * m**2 - n / 2) % 1
                if combined < 0.2:
                    complexity += np.sin(combined * np.pi*2) / (m * n + 0.5)
                elif combined < 0.6:
                    complexity += np.cos(combined * np.pi*3) / (m + n + 0.3)
                else:
                    complexity += (combined ** 3) / ((m + 1) * (n + 2))
        complexity *= 0.6 if (cap % 7 == 0) else 1.0
        if cap % 2 == 0 and cap % 3 == 0:
            priority_score = base + penalty * 0.7 + extra_penalty * 1.1 + complexity * 0.9
        elif cap % 4 == 0:
            priority_score = base + penalty * 1.3 + extra_penalty * 0.6 + complexity * 0.7
        elif cap % 6 == 0:
            priority_score = base + penalty * 0.9 + extra_penalty * 0.9 + complexity * 1.2
        else:
            priority_score = base + penalty + extra_penalty + complexity
        if priority_score < 0:
            priority_score = 0
        if priority_score > 10:
            priority_score = 10 - (priority_score - 10) * 0.2
        priorities[i] = priority_score
    return priorities
